1	//! Phase-D `Trace` implementations for types defined in this crate.
2	//!
3	//! Each impl enumerates the type's GC-bearing fields and either calls
4	//! `field.trace(m)` (delegating to the field's own `Trace` impl) or
5	//! `m.mark(field)` (when the field is a `Gc<T>` from `lua-gc`). During the
6	//! Phase A/B/C/D-0 window `GcRef<T>` is still an `Rc<T>` newtype rather
7	//! than the real `Gc<T>`, so the mark-queue path is not yet reachable —
8	//! method resolution dispatches through `Deref` to each underlying type's
9	//! own `trace` method.
10	
11	use lua_gc::{Marker, Trace};
12	use crate::gc::GcRef;
13	use crate::value::{LuaValue, LuaTable};
14	use crate::upval::{UpVal, UpValState};
15	use crate::string::LuaString;
16	use crate::proto::LuaProto;
17	use crate::closure::{LuaClosure, LuaLClosure, LuaCClosure};
18	use crate::userdata::LuaUserData;
19	use crate::value::LuaThread;
20	
21	/// Forwarder for `GcRef<T>`. Now that `GcRef` wraps a real `lua_gc::Gc<T>`
22	/// (D-1e), tracing must enqueue the box onto the gray queue via
23	/// `Marker::mark` — that is what flips its header color from White to Gray
24	/// and ultimately to Black during gray-queue drainage. The previous
25	/// `try_visit` short-circuit was a Phase A-D-0 workaround for the
26	/// `Rc`-backed handle (no header, no color), and produced a silent bug
27	/// post-D-1e: every GC-tracked allocation stayed White and was freed in
28	/// the sweep on the first `collectgarbage()`. Cycles are now handled
29	/// natively by the heap's gray-queue (Color::Gray check in `mark` makes
30	/// re-visits idempotent).
31	impl<T: Trace + 'static> Trace for GcRef<T> {
32	    fn trace(&self, m: &mut Marker) {
33	        m.mark(self.0);
34	    }
35	}
36	
37	/// LuaValue — central enum. Variants Nil/Bool/Int/Float/LightUserData carry
38	/// no GC; Str/Table/Function/UserData/Thread carry collectable payloads.
39	impl Trace for LuaValue {
40	    fn trace(&self, m: &mut Marker) {
41	        match self {
42	            LuaValue::Nil
43	            | LuaValue::Bool(_)
44	            | LuaValue::Int(_)
45	            | LuaValue::Float(_)
46	            | LuaValue::LightUserData(_) => {}
47	            LuaValue::Str(s) => s.trace(m),
48	            LuaValue::Table(t) => t.trace(m),
49	            LuaValue::Function(c) => c.trace(m),
50	            LuaValue::UserData(u) => {
51	                u.trace(m);
52	            }
53	            LuaValue::Thread(_t) => {
54	                // PORT NOTE: GcRef<LuaThread> is a placeholder unit type in
55	                // lua-types; the real LuaState lives in lua-vm and is traced
56	                // through GlobalState::mainthread / state.openupval, not
57	                // here.
58	            }
59	        }
60	    }
61	}
62	
63	/// LuaString — interned byte string. The `Rc<[u8]>` backing buffer is
64	/// owned, not GC-managed, so this impl is intentionally empty.
65	impl Trace for LuaString {
66	    fn trace(&self, _m: &mut Marker) {}
67	}
68	
69	/// UpVal — Open (refers to a thread stack slot by index) or Closed (owns a
70	/// LuaValue). The Open variant carries no direct GC reference; the slot it
71	/// points at is traced through the owning thread's stack walk.
72	impl Trace for UpVal {
73	    fn trace(&self, m: &mut Marker) {
74	        match &*self.state.borrow() {
75	            UpValState::Open { .. } => {}
76	            UpValState::Closed(v) => v.trace(m),
77	        }
78	    }
79	}
80	
81	/// LuaTable — array+hash entries plus optional metatable.
82	///
83	/// Weak-table semantics (Phase D-2):
84	///   * `__mode = "v"` — values are weak; mark keys only. Dead values get
85	///     pruned in the post-mark hook via [`crate::value::LuaTable::prune_weak_dead`].
86	///   * `__mode = "kv"` — both sides weak; trace neither. Both get pruned.
87	///   * `__mode = "k"` — keys are weak; trace NEITHER initially. The
88	///     post-mark ephemeron convergence pass walks each weak-key table's
89	///     entries and marks values only for entries whose keys are
90	///     independently reachable. Iterating to fixed point makes
91	///     reachability of value_i transitively depend on key_i — that's the
92	///     defining property of ephemerons.
93	///   * No `__mode` — trace both unconditionally.
94	impl Trace for LuaTable {
95	    fn trace(&self, m: &mut Marker) {
96	        const WEAK_KEYS: u8 = 1;
97	        const WEAK_VALUES: u8 = 1 << 1;
98	        let mode = self.weak_mode();
99	        let trace_keys = (mode & WEAK_KEYS) == 0;
100	        let trace_values = (mode & WEAK_VALUES) == 0 && trace_keys;
101	        let mut key = LuaValue::Nil;
102	        while let Some((k, v)) = self.next_pair(&key) {
103	            if trace_keys {
104	                k.trace(m);
105	            }
106	            if trace_values {
107	                v.trace(m);
108	            }
109	            key = k;
110	        }
111	        if let Some(mt) = self.metatable() {
112	            mt.trace(m);
113	        }
114	    }
115	}
116	
117	/// LuaProto — bytecode prototype. k (constants), p (child protos),
118	/// source, upvalue names, locvar names.
119	impl Trace for LuaProto {
120	    fn trace(&self, m: &mut Marker) {
121	        for v in self.k.iter() {
122	            v.trace(m);
123	        }
124	        for p in self.p.iter() {
125	            p.trace(m);
126	        }
127	        if let Some(src) = &self.source {
128	            src.trace(m);
129	        }
130	        for uv in self.upvalues.iter() {
131	            if let Some(name) = &uv.name {
132	                name.trace(m);
133	            }
134	        }
135	        for lv in self.locvars.iter() {
136	            lv.varname.trace(m);
137	        }
138	    }
139	}
140	
141	/// LuaLClosure — Lua closure carrying a Proto and its captured upvalues.
142	impl Trace for LuaLClosure {
143	    fn trace(&self, m: &mut Marker) {
144	        self.proto.trace(m);
145	        for uv in self.upvals.iter() {
146	            uv.borrow().trace(m);
147	        }
148	    }
149	}
150	
151	/// LuaClosure — dispatch to Lua/C variants; LightC is a bare function-ptr
152	/// index with no payload.
153	impl Trace for LuaClosure {
154	    fn trace(&self, m: &mut Marker) {
155	        match self {
156	            LuaClosure::Lua(l) => l.trace(m),
157	            LuaClosure::C(c) => c.trace(m),
158	            LuaClosure::LightC(_) => {}
159	        }
160	    }
161	}
162	
163	/// LuaCClosure — Rust-side C closure carrying captured upvalues.
164	impl Trace for LuaCClosure {
165	    fn trace(&self, m: &mut Marker) {
166	        for v in self.upvalues.iter() {
167	            v.trace(m);
168	        }
169	    }
170	}
171	
172	/// LuaUserData — boxed payload + optional metatable + user values.
173	impl Trace for LuaUserData {
174	    fn trace(&self, m: &mut Marker) {
175	        if let Some(mt) = self.metatable() {
176	            mt.trace(m);
177	        }
178	        for v in self.uv.iter() {
179	            v.trace(m);
180	        }
181	    }
182	}
183	
